function LFightObject:Create(heroData, parentTrans, gridPos, completeFunc)
	self._rootTrans = parentTrans
	self._heroData = heroData
	self._gridPos = gridPos

	self._completeFunc = completeFunc

	self._randZ = math.random(100, 999) * 0.0000001

	local actOn = heroData:GetActOn()
	if actOn == LFightConst.ACTON_TEAM_A then
		self._direction = LFightConst.DIRECTION_RIGHT
		self._side = LFightConst.SIDE_TEAM_A
	else
		self._direction = LFightConst.DIRECTION_LEFT
		self._side = LFightConst.SIDE_TEAM_B
	end

	if not self:InitData() then
		return false
	end

	if self:IsOnGridObj() then
		self:InitAllEffectData()
		self:InitActor()
		self:InitDisplay()
	end

	self:InitObjHud()

	self:SetHeroBgPos()

	return true
end

function LFightObject:ResetHeroData(heroData)
	self._heroData = heroData
	self._maxHP = heroData._maxHP
	self._curHp = heroData._hp

	if self._bloodStick then
		self._bloodStick:RefreshHpData(self._maxHP,self._curHp)
	end
end

function LFightObject:InitAllEffectData()
	if not self._heroData then
		return
	end

	local buffList = self._heroData:GetBuffList()
	for i, buff in ipairs(buffList) do
		local buffs = {}
		buffs.buffUniqueId = buff.buffUniqueId
		buffs.buffId = buff.buffId
		buffs.round = buff.round
		buffs.startRound = buff.startRound
		buffs.currentRound = buff.currentRound
		table.insert(self._buffList, buffs)
	end

	for k,v in pairs(self._heroData._blockList) do
		local block = table.clone(v)
		table.insert(self._blockList,block)
	end

	for k,v in pairs(self._heroData._shieldList) do
		local shield = table.clone(v)
		self._shieldList[shield.shieldUniqueId] = shield
	end

	for k,v in pairs(self._heroData._angerList) do
		local anger = table.clone(v)
		self._angerList[anger.buffUniqueId] = anger
	end

	self._canRelive = self._heroData._canRelive


	local pliesBuffList = self._heroData:GetPliesBuffList()
	for i,v in ipairs(pliesBuffList) do
		local buffUniqueIds = {}
		local buffUniqueIdMap = {}
		for idx,val in ipairs(v.buffUniqueIds) do
			table.insert(buffUniqueIds,val)
			buffUniqueIdMap[val] = true
		end
		table.insert(self._pliesBuffList,{
			buffUniqueIds = buffUniqueIds,
			buffUniqueIdMap = buffUniqueIdMap,
			buffUniqueIdCnt = #buffUniqueIds,
			buffId = v.buffId,
			round = v.round,
			round = v.round,
			startRound = v.startRound,
			currentRound = v.currentRound,
		})
	end
end

