function LFightObject:InitData()
	local heroData = self._heroData

	self._index = heroData:GetIndex()
	self._id = heroData:GetId()

	local isMonster = heroData:IsMonster()

	local aniShowEffRef = nil
	local objName = nil

	self._battleObjType = heroData:GetArtifactType()

	local refId = heroData:GetRefId()
	if self:IsOnGridObj() then

		-- 【C宠物系统】删掉宠物系统相关
		-- if self._battleObjType == LFightConst.OBJ_PET then
		-- 	local star = heroData:GetStar()
		-- 	local starRef = gModelPetSpace:GetPetStarRef(refId,star)
		-- 	local effectId = starRef.effectId
		-- 	aniShowEffRef = gModelPetSpace:GetPetShowRef(effectId)
		-- 	objName = ccLngText(aniShowEffRef.name)
		-- else
			if isMonster then
				local monRef = GameTable.MonsterAttrRef[refId]
				if not monRef then
					printErrorN("怪物不存在 refId" .. tostring(refId))
					return false
				end

				local effectId = heroData:GetShowEffId() --monRef.effectId
				aniShowEffRef = GameTable.CharacterEffectRef[effectId]
				if not aniShowEffRef then
					printErrorN(string.format("表现数据不存在怪物refID为%s,表现refId为%s" ,tostring(refId),tostring(effectId)))
					return false
				end
				objName = ccLngText(monRef.name)
				if string.isempty(objName) then
					objName = ccLngText(aniShowEffRef.name)
				end

				-- 获取怪物的缩放
				self._scale = tonumber(monRef.scale)
			else
				local skinId = heroData:GetSkinId()
				local heroEffectId
				if skinId and skinId>0 then --英雄皮肤
					heroEffectId = skinId
				else
					local heroRef = gModelHero:GetHeroRef(refId)
					if not heroRef then
						printErrorN("英雄不存在 refId" .. tostring(refId))
						return false
					end

					local form = heroData:GetForm()
					local star = heroData:GetStar()
					local starRef = gModelHero:GetHeroStarRef(refId,form,star)
					heroEffectId = starRef.effectId
				end

				aniShowEffRef = GameTable.CharacterEffectRef[heroEffectId]
				if not aniShowEffRef then
					printErrorN(string.format("表现数据不存在英雄refID为%s,表现refId为%s" ,tostring(refId),tostring(heroEffectId)))
					return false
				end
				objName = ccLngText(aniShowEffRef.name)
			end

		-- end


		self._curHp = heroData:GetHp()
		self._maxHP = heroData:GetMaxHp()
		self._refId = refId

		local showEffRefList = {}
		table.insert(showEffRefList,aniShowEffRef)
		local effectIdTwo = aniShowEffRef.skinState2
		if effectIdTwo and effectIdTwo > 0 then
			local temp = GameTable.CharacterEffectRef[effectIdTwo]
			table.insert(showEffRefList,temp)
		end

		self._objName = objName
		self._showEffRefList = showEffRefList
		self._sCardData = heroData:GetSCardData()

	end

	return true
end

function LFightObject:HasSCard()
	if self._sCardData and self._sCardData.scRefId > 0 then
		return true
	end
end

function LFightObject:GetCardRefId()
	return self._sCardData and self._sCardData.scRefId
end

---@return V_HeroEffectRef
function LFightObject:GetShowEffRef()
	local cnt = #self._showEffRefList
	local index = math.min(cnt ,self._showEffIndex)
	local showEffRef = self._showEffRefList[index]
	return showEffRef
end

function LFightObject:GetDeadInterval()
	local showEffRef = self:GetShowEffRef()
	return LxResPathUtil.GetSpineAniTime(showEffRef.prefabName, LSpineAniConst.die, 0)
end

---@return LDisplaySpine
function LFightObject:GetDisplayObj()
	local cnt = #self._displayObjList
	local index = math.min(cnt ,self._showEffIndex)
	return self._displayObjList[index]
end

--- 如果又变身的话，使用变身后的
function LFightObject:GetTransformDisplayObj()
	if self._newChangeIndex and self._newChangeIndex > 0 then
		local cnt = #self._displayObjList
		local index = math.min(cnt ,self._newChangeIndex)
		return self._displayObjList[index]
	end
	return self:GetDisplayObj()
end

function LFightObject:ChangeShowEffIndex(showEffIndex)
	if self._showEffIndex == showEffIndex then
		return
	end
	self._showEffIndex = showEffIndex

	if not self._isChangeSpine then
		self:RefreshHeroShowEff()
	end
end

function LFightObject:RefreshHeroShowEff()
	local showEffIndex = self._showEffIndex

	local cnt = #self._displayObjList
	showEffIndex = math.min(showEffIndex,cnt)
	--printErrorN("cur showEffect index "..showEffIndex)

	for k,v in ipairs(self._displayObjList) do
		v:SetVisible(k == showEffIndex)
	end
end

