function LFightObject:InitActor()
	self._aniActor = LFightAniActor:New(self._battleUnit,self)
	self._moveActor = LFightMoveActor:New(self._battleUnit,self)
end

function LFightObject:InitObjHud()
	self._objHud = LFightObjectHud:New(self._battleUnit:GetBattleCache(),self)
end

function LFightObject:CreateBg(trans)
	local heroBgName = string.format("hero_bg_%s_%s",self._side,self._index)
	local heroBgRoot = CS.NewObject(heroBgName,self._rootTrans)
	local pos = self._rootTrans.position
	heroBgRoot.position = pos

	local heroBgRootTrans = heroBgRoot.transform
	local spRender = heroBgRootTrans:GetComponent(typeSpriteRenderer)
	if not spRender then
		spRender = heroBgRoot.gameObject:AddComponent(typeSpriteRenderer)
	end
	spRender.sortingLayerName = "Ground"
	self._heroBgTrans = heroBgRootTrans
	self:SetHeroBgVisiable(false)
	self._heroBgSpriteRenderer = spRender
	self:SetHeroBg_Normal()
end

--- 处于待机状态（未受击、未出手）
function LFightObject:SetHeroBg_Normal()
	local spriteName = self._heroBgSpriteMap[LFightObject.HEROBG_SP_NORMAL]
	self:SetSpriteRenderer(self._heroBgTrans, spriteName)
	self:UpdateHeroBgLocalPosition()
end

--- 处于出手的角色（不跟随角色移动）
function LFightObject:SetHeroBg_Attack()
	local spriteName = self._heroBgSpriteMap[LFightObject.HEROBG_SP_ATTACK]
	self:SetSpriteRenderer(self._heroBgTrans, spriteName)
	self:UpdateHeroBgLocalPosition()
end

--- 处于受击范围的阵位（有角色站）
function LFightObject:SetHeroBg_Hit()
	local spriteName = self._heroBgSpriteMap[LFightObject.HEROBG_SP_HIT]
	self:SetSpriteRenderer(self._heroBgTrans, spriteName)
	self:UpdateHeroBgLocalPosition()
end

function LFightObject:UpdateHeroBgLocalPosition()
	if not self._objRoot then return end
	if not self._rootTrans then return end

	self._heroBgTrans.localPosition = self._objRoot.localPosition
end

function LFightObject:InitDisplay()
	local name = string.format("hero_%s_%s",self._side,self._index)
	local objRoot = CS.NewObject(name,self._rootTrans)
	self:CreateBg(objRoot)
	self._objRoot = objRoot

	local constObjName = string.format("c_hero_%s_%s",self._side,self._index)
	local constObjRoot = CS.NewObject(constObjName,self._rootTrans)
	self._constObjRoot = constObjRoot

	local displayObjList = {}
	local isRight = self._side == LFightConst.ACTON_TEAM_B
	local useRightSpine = false

	local changeStatus = self._heroData:GetChangeStatus()

	for k,v in ipairs(self._showEffRefList) do
		local spine = v.prefabName
		if isRight and not string.isempty(v.prefabNameRight) then
			spine = v.prefabNameRight
			useRightSpine = true
		end

		if not string.isempty(spine) then
			---@type LDisplaySpine
			local dp = LDisplaySpine:New()
			table.insert(displayObjList,dp)
			dp:CreateSpine(objRoot, spine)
			dp:SetScale(self._scale)
			dp:SetLoadedFunction(function()
				dp:SetAlpha(0)
				self:OnLoaded(self._isShowDp)
			end)
			dp:SetAnimationCompleteFunc(function(...)
				self:OnAnimationComplete(...)
			end)

			if changeStatus then
				dp:SetChangeStatus(changeStatus)
			end


		end
	end

	self._useRightSpine = useRightSpine

	self._displayObjList = displayObjList

	self:SetLocalPosValue(self._gridPos)

end
function LFightObject:OnAnimationComplete(animateName)
	if animateName == LSpineAniConst.hit1 then
		self:PlayIdleAni()
	elseif animateName == LSpineAniConst.resurrected then
		local playTreatStatus = self._playTreatStatus
		self._playTreatStatus = false
		if playTreatStatus and not self:IsDead() then
			if self._aniActor then
				local aniName = self._aniActor:GetAniName()
				if aniName ~= LSpineAniConst.idle then
					self:PlayIdleAni()
				end
			end
		end
	end
end

function LFightObject:StartLoadDp()
	-- 【G公共支持】删除神器功能相关数据
	-- local objType = self._battleObjType
	-- if objType == LFightConst.OBJ_ARTIFACT then
	-- 	self:PreloadArtifactEff()
	-- 	self:OnBattleObjLoaded()
	if self:IsOnGridObj() then
		self._loadCnt = #self._displayObjList
		for k,v in ipairs(self._displayObjList) do
			v:StartLoad()
		end

		self:LoadBirthEff()
	else
		self:OnBattleObjLoaded()
	end
end

function LFightObject:OnLoaded(isCreateBlood)

	self._loadCnt = self._loadCnt - 1
	if self._loadCnt > 0 then
		return
	end

	self:RefreshHeroShowEff()

	self:InitBtObjectView()

	self:SetPosition(LFightConst.DEFAULT_LOADED_POS)
	self:SetDirection(self._direction)
	if isCreateBlood then
		-- 【G公共支持】删除暗黑战争相关数据
		-- if self:IsDarkWar() then
		-- 	self:CreateDWBloodStick()
		-- else
			self:CreateBloodStick()
		-- end
	end

	local order = self:GetRenderOrder()
	self:SetRenderOrder(order)

	--出生动画时候才显示
	self:SetObjAlpha(0)

	if self._isUpperLayer then
		self:ToUpperLayer()
	else
		self:ToLowerLayer()
	end

	self:AddClickFun()

	self:CheckLoadEnd()
	--self:OnBattleObjLoaded()
end


