--血条创建
function LFightObject:CreateBloodStick()
	if self._bloodStick then
		return
	end



	local bloodStick = LBloodStick:New()
	local barType = self._side == LFightConst.SIDE_TEAM_A and 0 or 1
	local trans = self._objRoot
	local topNodePos = self:GetTopNodePos()
	local nowPos = trans.position

	local bloodData =
	{
		level = self._heroData:GetLevel(),
	}
	local refId = self._heroData:GetRefId()
	local ref =nil
	-- 【C宠物系统】删掉宠物系统相关
	-- if self._battleObjType == LFightConst.OBJ_PET then
	-- 	ref =gModelPetSpace:GetPetConfigByTypeAndKey(ModelPetSpace.MagicPetRef, refId)
	-- 	bloodData.type = "pet"
	-- else
		local isMonster = self._heroData:IsMonster()
		if isMonster then
			ref = gModelHero:GetMonsterAttrByRefId(refId)
		else
			ref = gModelHero:GetHeroRef(refId)
		end
	-- end


	bloodData.career = ref.careerType
	bloodData.race = ref.raceType
	bloodData.blockList = self._heroData:GetBlockList()
	bloodData.shieldList = self._heroData:GetShieldList()
	local curHp = self._heroData:GetHp()

	bloodStick:CreateBloodStick(barType,self._maxHP,curHp,bloodData)
	bloodStick:SetHeroTrans(trans,topNodePos - nowPos)
	bloodStick:SetVisible(false)

	if self._roundCd then
		self:UpdateCdRound(self._roundCd)
	end

	self._bloodStick = bloodStick
	bloodStick:StartLoad()
end

function LFightObject:CreateDWBloodStick()
	if self._bloodStick then
		return
	end


	local bloodStick = LDWBloodStick:New()
	local trans = self._objRoot
	local topNodePos = self:GetTopNodePos()
	local nowPos = trans.position

	local bloodData =
	{
		name = self._heroData:GetTeamName(),
		maxHp = self._maxHP,
		curHp = self._heroData:GetHp()
	}

	bloodStick:CreateBloodStick(bloodData)
	bloodStick:SetHeroTrans(trans,topNodePos - nowPos)
	bloodStick:SetVisible(false)
	self._bloodStick = bloodStick
	bloodStick:StartLoad()
end

