function LFightObject:OnSkillEnd()
	if self:IsDestroy() then return end

	local curShowCnt = self._curShowCnt or 0
	curShowCnt= curShowCnt - 1
	self._curShowCnt = curShowCnt

	if curShowCnt > 0 then
		return
	end

	self:ResetRender(true)

	--- 技能播放结束需要恢复隐匿状态的显示
	self:UpdateAlpha()
end

function LFightObject:OnSkillStart()
	local curShowCnt = self._curShowCnt or 0
	curShowCnt= curShowCnt + 1
	self._curShowCnt = curShowCnt

	--- 若处于隐匿状态下，则需要显示出来后再播放
	self:SetObjAlpha(1)
end

