function LFightObject:SynOfflineState(time)
	if self._battleObjType ~= LFightConst.OBJ_NORMAL then
		return
	end
	local heroData = self:GetHeroData()
	local hp = heroData:GetHp()
	self._curHp = hp
	self:UpdateHpProgress(hp)
	local isDead = heroData:IsDead()
	if isDead then
		self:SetObjAlpha(0)
		--self:ShowBloodStick(false)

		self:SetHideBloodKey("dead")
		self:DestroyAllBuff()
		self:ShowDeadBuff()
		self._bDeaded = true
		self._deadActionEnd = true
		self._bDeadEnd = true

		self._changeWaitCb = nil
		self._isChangeSpine = false
	end
end
function LFightObject:UpdateBlood(curHp,playNum,time)
	local maxHp = self._maxHP
	curHp = math.max(0,curHp)
	curHp = math.min(maxHp,curHp)

	self:ClearBloodList()
	self._bloodDataList = gModelSkill:FormatBloodPlayData(self._curHp,curHp,time,playNum)
end

function LFightObject:ClearBloodList()
	if self._bloodDataList then --立即更新到最新血量
		local last = self._bloodDataList[#self._bloodDataList]
		if last then
			self._curHp = last.curHp
			self:UpdateHpProgress(last.curHp)
			self._battleUnit:RefreshTeamCurHpPercent(self._side)
		end
		self._bloodDataList =nil

	end
end

function LFightObject:UpdateBloodInternal(time)
	if not self._bloodDataList then
		return
	end
	local dataList = self._bloodDataList

	local first = dataList[1]
	if not first then
		return
	end

	if first.startTime > time then
		return
	end
	self._curHp = first.curHp
	self:UpdateHpProgress(first.curHp)

	self._battleUnit:RefreshTeamCurHpPercent(self._side)

	table.remove(self._bloodDataList,1)

end

function LFightObject:DoBuffUpdate(buff,etype)
	if not buff then return end

	local buffEffShowNumData = gModelBattle:GetBuffEffShowNum(buff.buffId)
	if buffEffShowNumData then
		self:DoPliesBuffUpdate(buff,etype)
	else
		self:DoCommonBuffUpdate(buff,etype)
	end

	self._isBuffDirty = true

	self:CheckShowBlood()

	self:RefreshShowEffIndex()
end

function LFightObject:DoStatisticsUpdate(data)
	if not self._statisticsMap then
		self._statisticsMap = {}
	end
	self._statisticsMap[data.buffUniqueId] = data
end

function LFightObject:DoRemoveStatistics(buffUniqueId)
	if not self._statisticsMap then
		self._statisticsMap = {}
	end
	self._statisticsMap[buffUniqueId] = nil
end

--- 通用 buff
function LFightObject:DoCommonBuffUpdate(buff,etype)
	local index = nil
	for i, buffData in ipairs(self._buffList) do
		if buffData.buffUniqueId == buff.buffUniqueId then
			index = i
			break
		end
	end

	local logCtrl = self._battleUnit:GetLogCtrl()
	local isDel = etype == LFightConst.BUFF_TYPE_REMOVE
	if isDel then
		if index then
			table.remove(self._buffList,index)

			if logCtrl:IsLogOpen() then
				local buffName = gModelSkill:GetBuffName(buff.buffId)
				logCtrl:LogNormal(string.format("hero: %s remove buff buffId %s uniqueid %s,name %s",self._id,buff.buffId,buff.buffUniqueId,buffName))
			end
		else
			if logCtrl:IsLogOpen() then
				logCtrl:LogError(string.format("failed remove buff buffId %s uniqueid %s",buff.buffId,buff.buffUniqueId))
			end
		end
	else
		if index then
			self._buffList[index] = buff
		else
			table.insert(self._buffList,buff)
		end
		if logCtrl:IsLogOpen() then
			local buffName = gModelSkill:GetBuffName(buff.buffId)
			logCtrl:LogNormal(string.format("hero: %s add or update buff buffId %s uniqueid %s,name %s",self._id,buff.buffId,buff.buffUniqueId,buffName))
		end
	end
end

--- 层数 buff
function LFightObject:DoPliesBuffUpdate(buff,etype)
	local index
	local buffId = buff.buffId
	for i,buffData in ipairs(self._pliesBuffList) do
		if buffData.buffId == buffId then
			index = i
			break
		end
	end

	local logCtrl = self._battleUnit:GetLogCtrl()
	local buffUniqueId = buff.buffUniqueId
	local isDel = etype == LFightConst.BUFF_TYPE_REMOVE
	if isDel then
		if index then
			local buffData = self._pliesBuffList[index]
			buffData.buffUniqueIdMap[buffUniqueId] = nil
			local buffUniqueIdIdx
			for i,v in ipairs(buffData.buffUniqueIds) do
				if buffUniqueId == v then
					buffUniqueIdIdx = i
					break
				end
			end
			if buffUniqueIdIdx and buffUniqueIdIdx > 0 then
				table.remove(buffData.buffUniqueIds,buffUniqueIdIdx)
			end
			local buffUniqueIdCnt = buffData.buffUniqueIdCnt - 1
			if buffUniqueIdCnt < 1 then
				table.remove(self._pliesBuffList,index)

				if logCtrl:IsLogOpen() then
					local buffName = gModelSkill:GetBuffName(buffId)
					logCtrl:LogNormal(string.replace("hero:#a1# remove Plies buff buffId:#a2#,name:#a3#",self._id,buffId,buffName))

				end
			else
				buffData.buffUniqueIdCnt = buffUniqueIdCnt

				if logCtrl:IsLogOpen() then
					local buffName = gModelSkill:GetBuffName(buffId)
					logCtrl:LogNormal(string.replace("hero:#a1#,sub plies buff cnt buffId:#a2#,sub uniqueid:#a3#,name:#a4#,leftCnt:#a5#",
							self._id,buffId,buffUniqueId,buffName,buffUniqueIdCnt))

				end
			end
		else
			if logCtrl:IsLogOpen() then
				logCtrl:LogError(string.format("failed remove Plies buff buffId %s uniqueid %s",buffId,buffUniqueId))
			end
		end
	else
		if index then
			local buffUniqueIdCnt = 0
			local buffData = self._pliesBuffList[index]
			if not buffData.buffUniqueIdMap[buffUniqueId] then
				buffData.buffUniqueIdMap[buffUniqueId] = true
				table.insert(buffData.buffUniqueIds,buffUniqueId)
				buffUniqueIdCnt = buffData.buffUniqueIdCnt + 1
				buffData.buffUniqueIdCnt = buffUniqueIdCnt
			end
			if logCtrl:IsLogOpen() then
				local buffName = gModelSkill:GetBuffName(buffId)
				logCtrl:LogNormal(string.replace("hero:#a1# update Plies buff buffId:#a2#,name:#a3#,buffCnt:#a4#",self._id,buffId,buffName,buffUniqueIdCnt))
			end
		else
			local buffData = {
				buffUniqueIds = {buffUniqueId},
				buffUniqueIdMap = {
					[buffUniqueId] = true,
				},
				buffUniqueIdCnt = 1,
				buffId = buffId,
				round = buff.round,
				startRound = buff.startRound,
				currentRound = buff.currentRound,
			}
			table.insert(self._pliesBuffList,buffData)
			if logCtrl:IsLogOpen() then
				local buffName = gModelSkill:GetBuffName(buffId)
				logCtrl:LogNormal(string.replace("hero:#a1# add Plies buff buffId:#a2#,name:#a3#,buffCnt:#a4#",self._id,buffId,buffName,1))
			end
		end
	end
end

function LFightObject:IsBuffDirty()
	return self._isBuffDirty
end

function LFightObject:RefreshAfter()
	if not self._isBuffDirty then
		return
	end

	self._isBuffDirty = false

	self:RefreshRelativeData()

	self:RefreshAllBuffEffect()

	self:ShowBuffInfo()

	FireEvent(EventNames.BUFF_DETAILS_UPDATE,self._heroData)
end

function LFightObject:RefreshRelativeData()
	local buffUIdMap = {}
	for k,v in pairs(self._buffList) do
		buffUIdMap[v.buffUniqueId] = true
	end

	local buffPliesUIdMap = {}
	for k,v in pairs(self._pliesBuffList) do
		for idx,val in ipairs(v.buffUniqueIds) do
			buffPliesUIdMap[val] = true
		end
	end

	local buffUniqueId
	local newList = {}
	for k, v in pairs(self._shieldList) do
		buffUniqueId = v.buffUniqueId
		if buffUIdMap[buffUniqueId] or buffPliesUIdMap[buffUniqueId] then
			newList[v.shieldUniqueId] = v
		end
	end
	self._shieldList = newList


	newList = {}
	for k,v in pairs(self._angerList) do
		buffUniqueId = v.buffUniqueId
		if buffUIdMap[buffUniqueId] or buffPliesUIdMap[buffUniqueId] then
			newList[buffUniqueId] = v
		end
	end
	self._angerList = newList

	newList = {}
	for k, v in ipairs(self._blockList) do
		buffUniqueId = v.buffUniqueId
		if buffUIdMap[buffUniqueId] or buffPliesUIdMap[buffUniqueId] then
			table.insert(newList,v)
		end
	end
	self._blockList = newList
end

function LFightObject:RefreshAllBuffEffect()
	if self._bDeaded then
		self:ShowDeadBuff()
	else
		self:RefreshBuffShow()
	end
	self:ChangeWellOrBadBuffCount()
	self:RefreshFreeze()
	self:RefreshAngerShow()
	self:RefreshBlockShow()
	self:RefreshShieldShow()

	self:RefreshBuffBar()

	self:RefreshShowEffIndex()
end

function LFightObject:RefreshShowEffIndex()
	local showEffIndex = 1
	local colorState = 1
	local isChangeSpine = false
	--local changeWaitTime = -1
	for k,v in ipairs(self._buffList) do
		local buffRef = gModelSkill:GetBuffRef(v.buffId)
		if buffRef then
			if buffRef.specialShow == 1 then
				if not isChangeSpine then
					if v.round > 0 then
						isChangeSpine = true
						if self._showEffIndex == 1 then
							showEffIndex = 2
						elseif self._showEffIndex == 2 then
							showEffIndex = 1
						end
					else
						showEffIndex = 2
					end
--[[					local expressionId,showState = gModelSkill:GetBuffSkillData(v.buffId,self:GetSkinId())
					if expressionId then
						local expressionData = gModelSkill:GetExpressConfigData(expressionId)
						if expressionData and #expressionData.effectList > 0 then
							local calcTime = 0
							local ref
							for idx,val in ipairs(expressionData.effectList) do
								ref = gModelSkill:GetSkillVfxRef(val)
								if ref then
									calcTime = calcTime + ref.playTime + ref.dissipateTime
								end
							end
							changeWaitTime = calcTime
						end
					end]]
				end
			elseif buffRef.specialShow == 2 then
				colorState = 2
			end
		end
	end

	if self._isChangeSpine then return end

	self._newChangeIndex = showEffIndex
	self._isChangeSpine = isChangeSpine
	local callBackFunc = function()
		if self:IsDead() then return end
		self:ChangeShowEffIndex(showEffIndex)
		self:SetDisplayColor(colorState)
	end
	if isChangeSpine then
		self._changeWaitCb = callBackFunc
	else
		callBackFunc()
	end
end

function LFightObject:CheckIsHasChangeWaitCb()
	local changeWaitCb = self._changeWaitCb
	self._changeWaitCb = nil
	if changeWaitCb then
		self._isChangeSpine = false
		if self:IsDead() then
			return
		end
		changeWaitCb()
	end
end

function LFightObject:GetChangeSpineState()
	return self._isChangeSpine
end

function LFightObject:SetDisplayColor(colorState)
	if self._colorState == colorState then
		return
	end

	self._colorState = colorState


	local color = colorState == 1 and Color.New(1, 1, 1, 1) or Color.New(0.3,0.3,0.3,1)

	for k,v in ipairs(self._displayObjList) do
		v:SetColor(color,true)
	end
end

function LFightObject:InitAllBuffEffect()
	if self._bDeaded then
		self:ShowDeadBuff()
	else
		self:RefreshBuffShow()
	end
	self:ChangeWellOrBadBuffCount()
	self:RefreshAngerShow()
	self:RefreshBlockShow()
	self:RefreshShieldShow()
end

function LFightObject:RefreshFreeze()

	if self._bDeaded then
		return
	end
	local logCtrl = self._battleUnit:GetLogCtrl()

	local buffId
	local isFreeze = false
	for k,v in ipairs(self._buffList) do
		buffId = v.buffId
		isFreeze = gModelBattle:IsFreezeBuff(buffId)
		if isFreeze then
			break
		end
	end

	if self._isFreeze == isFreeze then
		return
	end
	self._isFreeze = isFreeze
	self._aniActor:SetFreeze(isFreeze)

	if logCtrl:IsLogOpen() then
		logCtrl:LogError(string.format("freeze state %s, buffId %s, heroId: %s",isFreeze,buffId,self._id))
	end

end

function LFightObject:RefreshBuffShow()
	if self._bDeaded then return end

	self:RefreshCommonBuffShow()
	self:RefreshPliesBuffShow()
end

function LFightObject:RefreshCommonBuffShow()
	local buffActList = {}
	local showList={}
	local showUniqueMap ={}
	for k,v in ipairs(self._buffList) do
		local refId = v.buffId
		local isOk = true
		---@type V_BuffRef
		local buffRefData = gModelBattle:GetBuffRef(refId)
		if buffRefData then
			local buffEffShowPos = buffRefData.buffEffShowPos
			if buffEffShowPos == LFightConst.BUFF_POS_SELF or buffEffShowPos == LFightConst.BUFF_POS_OTHER then
				isOk = false
			end
		end
		if isOk then
			local buffEffShowType = gModelBattle:GetBuffEffShowTypeById(refId)
			local isDeadShow = gModelBattle:IsShowAfterDead(refId) --圣灵buff 不在这里展示
			if not isDeadShow then
				local buff = showList[buffEffShowType] --同类型只显示一个
				if not buff then
					showList[buffEffShowType] = v
					showUniqueMap[v.buffUniqueId] = true
				end
			end
			local buffAct = gModelSkill:GetBuffAct(refId)
			if buffAct then
				--if LOG_INFO_ENABLED then
				--    print("--------------------------buff act "..refId)
				--end
				local actData = buffActList[refId]
				if not actData then
					actData = {
						cnt = 0,
						buffAct = buffAct
					}
					buffActList[refId] = actData
				end
				actData.cnt = actData.cnt + 1
			end
		end
	end

	local destroyEffMap = {}
	local existMap ={}
	local cnt = #self._curBuffEffectList
	for k = cnt,1,-1 do
		local eff = self._curBuffEffectList[k]
		local uniqueid = eff:GetBuffUniqueId()
		if not showUniqueMap[uniqueid] and not self:IsSpecialBuffEff(uniqueid) then
			destroyEffMap[uniqueid] = true
			eff:Destroy()
			table.remove(self._curBuffEffectList,k)
		else
			existMap[uniqueid] = true
		end
	end

	for k,v in pairs(showList) do
		if not existMap[v.buffUniqueId] then
			self:CreateBuffEffect(v)
		end
	end

	local material = nil
	for k,v in pairs(showList) do
		local temp = gModelSkill:GetBuffMat(v.buffId)
		if not string.isempty(temp) then
			material = temp
			if self._curMat == material then
				break
			end
		end
	end

	self:SetSpineMat(material)
	self:RefreshBuffAct(buffActList)
end

function LFightObject:RefreshPliesBuffShow()
	local curPliesBuffEffMap = {}
	for i,v in pairs(self._pliesBuffEffectList) do
		curPliesBuffEffMap[v:GetBbuffUniqueIdCnt()] = true
	end

	local showList = {}
	local destroyPliesEffMap = {}
	local isEmpty = #self._pliesBuffList < 1
	for i,v in ipairs(self._pliesBuffList) do
		local refId = v.buffId
		local isOk = true
		---@type V_BuffRef
		local buffRefData = gModelBattle:GetBuffRef(refId)
		if buffRefData then
			local buffEffShowPos = buffRefData.buffEffShowPos
			if buffEffShowPos == LFightConst.BUFF_POS_SELF or buffEffShowPos == LFightConst.BUFF_POS_OTHER then
				isOk = false
			end
		end
		if isOk then
			if v.buffUniqueIdCnt < 1 then
				destroyPliesEffMap[refId] = true
			else
				if not curPliesBuffEffMap[v.buffUniqueIdCnt] then
					destroyPliesEffMap[refId] = true
				end
				table.insert(showList,v)
			end
		end
	end

	local destroyEffMap = {}
	local existMap = {}
	local cnt = #self._pliesBuffEffectList
	for k = cnt,1,-1 do
		local eff = self._pliesBuffEffectList[k]
		if isEmpty then
			eff:Destroy()
			table.remove(self._pliesBuffEffectList,k)
		else
			local buffId = eff:GetBuffId()
			if destroyPliesEffMap[buffId] then
				destroyEffMap[buffId] = true
				eff:Destroy()
				table.remove(self._pliesBuffEffectList,k)
			else
				existMap[buffId] = true
			end
		end
	end

	for k,v in pairs(showList) do
		if not existMap[v.buffId] then
			self:CreatePliesBuffEffect(v)
		end
	end
end

function LFightObject:SetSpineMat(mat)
	if self._curMat == mat then
		return
	end

	--printInfoN(string.format("set mat %s",mat))
	self._curMat = mat

	for k,v in ipairs(self._displayObjList) do
		if mat then
			v:SetSpineMat(mat)
		else
			v:SetSpineDefaultMat()
		end
	end

end

--删除buff光效
function LFightObject:RemoveBuffEffect(buff)
	if not buff or not self._curBuffEffectList then
		return
	end

	for i, buffEff in ipairs(self._curBuffEffectList) do
		local effBuffUniqueId = buffEff:GetBuffUniqueId()
		if effBuffUniqueId == buff.buffUniqueId then
			buffEff:Destroy()
			table.remove(self._curBuffEffectList,i)
			break
		end
	end
end

---添加buff光效
function LFightObject:CreateBuffEffect(buff)
	if not buff then return end
	--if not self._displayObj or not self._displayObj:IsDpValid() then
	--	return
	--end
	local effectName =  gModelBattle:GetbuffEffShowById(buff.buffId)
	if string.isempty(effectName) then return end
	--if LOG_INFO_ENABLED then
    --
	--	local str = string.format("heroId %s|buffid %s|buffEffect %s|buffUid %s",self._id,buff.buffId,buff.buffUniqueId,effectName)
	--	printErrorN(str)
	--end
	local dir =  self:GetActOn() == 2 and LFightConst.DIRECTION_LEFT or LFightConst.DIRECTION_RIGHT
	local data = {
		buffId = buff.buffId,
		root = self._objRoot,-- self._displayObj:GetDisplayTrans(),
		effectName = effectName,
		localPos = self:GetBuffEffShowPos(buff.buffId,self._scale),
		dir = dir,
		order = self:GetRenderOrder(),
		buffUniqueId = buff.buffUniqueId,
		scale = self:GetObjScale(),
	}
	self:AddBattleBuff(data)
end

function LFightObject:AddBattleBuff(data)
	local buffEff = LFightBuff:New(self._battleUnit)
	buffEff:ShowEffect(data,self)
	table.insert(self._curBuffEffectList,buffEff)
end

function LFightObject:CreatePliesBuffEffect(buff)
	if not buff then return end

	local buffId = buff.buffId
	local buffEffShowNumData = gModelBattle:GetBuffEffShowNum(buffId)
	if not buffEffShowNumData then return end

	local buffUniqueIdCnt = buff.buffUniqueIdCnt
	local buffEffShow = buffEffShowNumData[buffUniqueIdCnt]
	if not buffEffShow then return end

	local dir = self:GetActOn() == 2 and LFightConst.DIRECTION_LEFT or LFightConst.DIRECTION_RIGHT
	local data = {
		buffId = buff.buffId,
		buffUniqueIdCnt = buff.buffUniqueIdCnt,
		root = self._objRoot,-- self._displayObj:GetDisplayTrans(),
		effectName = buffEffShow.effRes,
		localPos = self:GetBuffEffShowPos(buff.buffId,self._scale),
		dir = dir,
		order = self:GetRenderOrder(),
		buffUniqueId = buff.buffUniqueId,
		scale = self:GetObjScale(),
	}
	self:AddBattlePliesBuff(data)
end

function LFightObject:AddBattlePliesBuff(data)
	local buffEff = LFightBuff:New(self._battleUnit)
	buffEff:ShowEffect(data,self)
	table.insert(self._pliesBuffEffectList,buffEff)
end

function LFightObject:IsSpecialBuffEff(uniqueid)
	if not self._specialEffMap then
		self._specialEffMap =
		{
			[LFightConst.BATTLE_EFFECT_BUFF_FAVORABLE] = true,
			[LFightConst.BATTLE_EFFECT_BUFF_HARMFUL] = true,
			[LFightConst.BATTLE_EFFECT_CAN_RELIVE] = true,
		}
	end

	return self._specialEffMap[uniqueid] or false
end

function LFightObject:GetBuffEffShowPos(buffId,scale)
	local buffEffShowPos = tonumber(gModelBattle:GetBuffEffShowPosById(buffId))
	return self:GetBuffEffShowPosByBuffEffShowPos(buffEffShowPos,scale)
end

function LFightObject:GetBuffEffShowPosByBuffEffShowPos(buffEffShowPos,scale)
	local offectY = 0.12   -- 头顶偏移值
	local topNodePos = self:GetTopNodeOffset()
	scale = scale or 1
	local topNodePosY = topNodePos.y * scale
	offectY = offectY * scale
	if buffEffShowPos == LFightConst.BUFF_POS_HEAD then
		return Vector3(topNodePos.x,topNodePosY - offectY,0)
	elseif buffEffShowPos == LFightConst.BUFF_POS_BODY then
		local hight = topNodePosY / 2
		return Vector3(topNodePos.x,hight,0)
	elseif buffEffShowPos == LFightConst.BUFF_POS_FOOT then
		return Vector3.zero
	end
end

function LFightObject:ChangeWellOrBadBuffCount()
	if self._bDeaded then
		return
	end

	local totalWell= 0
	local totalBad = 0

	for k,v in ipairs(self._buffList) do
		local buffRef = gModelBattle:GetBuffRef(v.buffId)
		local universalBuffShow =buffRef and buffRef.universalBuffShow --1 增益buff 2 减益buff
		if universalBuffShow == 1 then
			totalWell = totalWell+1
		elseif universalBuffShow == 2 then
			totalBad = totalBad +1
		end
	end

	totalWell = totalWell>4 and 4 or totalWell
	totalBad =  totalBad>4 and 4 or totalBad

	if self._wellBuffCount ~= totalWell then
		self._wellBuffCount = totalWell
		self:UpdateUniversalBuffShowEffect(true)
	end

	if self._badBuffCount ~= totalBad then
		self._badBuffCount = totalBad
		self:UpdateUniversalBuffShowEffect(false)
	end
end

--通用增减益buff表现
function LFightObject:UpdateUniversalBuffShowEffect(isWell)
	local count = isWell and self._wellBuffCount or self._badBuffCount

	local removeData =
	{
		buffUniqueId = isWell and LFightConst.BATTLE_EFFECT_BUFF_FAVORABLE or LFightConst.BATTLE_EFFECT_BUFF_HARMFUL
	}

	self:RemoveBuffEffect(removeData)

	if count<= 0 then
		return
	end
	local root = self._objRoot -- self._displayObj:GetDisplayTrans()
	local dir = self:GetActOn() == 2 and LFightConst.DIRECTION_LEFT or LFightConst.DIRECTION_RIGHT
	local order = self:GetRenderOrder() + 1
	local data = nil
	if isWell then
		data = {
			buffUniqueId = LFightConst.BATTLE_EFFECT_BUFF_FAVORABLE,
			root = root,
			dir = dir,
			order = order,
			effectName = "fx_buff_zengyi_" .. count,
		}
	else
		data = {
			buffUniqueId = LFightConst.BATTLE_EFFECT_BUFF_HARMFUL,
			root = root,
			dir = dir,
			order = order,
			effectName = "fx_buff_jianyi_" .. count,
		}
	end

	self:AddBattleBuff(data)
end
