function LFightObject:AddShieldData(shieldData)
	self._shieldList[shieldData.shieldUniqueId] = shieldData

	self:RefreshShieldShow()
end

function LFightObject:RemoveShieldData(shield)
	if not shield then
		return
	end

	for i, v in pairs(self._shieldList) do
		if v.buffUniqueId == shield.buffUniqueId then
			self._shieldList[v.shieldUniqueId] = nil
			break
		end
	end

	self:RefreshShieldShow()
end

--function LFightObject:GetShieldDataByUniqueId(shieldUniqueId)
--	return self._shieldList[shieldUniqueId]
--end

function LFightObject:UpdateShieldData(shieldData)
	local shield = self._shieldList[shieldData.shieldUniqueId]
	if shield then
		local curHP = shield.curHP + shieldData.hurt
		if curHP<=0 then
			self._shieldList[shieldData.shieldUniqueId] = nil
		else
			shield.curHP = curHP
		end
	end

	self:RefreshShieldShow()
end

function LFightObject:RefreshShieldShow()
	local curShieldV = 0
	local maxShieldV = 0

	for k,v in pairs(self._shieldList) do
		curShieldV = curShieldV + v.curHP
		maxShieldV = maxShieldV + v.maxHP
	end

	self:ShowNormalShield({curShieldV = curShieldV,maxShieldV = maxShieldV})
end

function LFightObject:UpdateBuffData(effect)
	for k, v in ipairs(self._buffList) do
		if v.buffUniqueId == effect.buffUniqueId then
			v.round = effect.round
			break
		end
	end
end

--- 判断是否有buff需要再受击时显示
function LFightObject:CheckHasHitBuffEffShow(ht)
	if not self._buffList or #self._buffList < 1 then return false end
	local buffId
	for i,v in ipairs(self._buffList) do
		buffId = v.buffId
		if buffId and buffId > 0 then
			---@type V_BuffRef
			local buffRef = gModelSkill:GetBuffRef(buffId)
			if buffRef and gModelSkill:CheckIsHitShowBuff(buffId) and not string.isempty(buffRef.buffEffShow) then
				if gModelSkill:CheckNeedShowDamageBuffEff(buffId,ht) then
					return true,buffRef
				end
			end
		end
	end
	return false
end
