function LFightObject:OnUpdateBuffRound(nowRound)
	for i, buff in ipairs(self._buffList) do
		local surplusRound = nowRound - buff.startRound
		if surplusRound < 0 then surplusRound = 0 end
		buff.currentRound = buff.round - surplusRound
	end
	for i,buff in ipairs(self._pliesBuffList) do
		local surplusRound = nowRound - buff.startRound
		if surplusRound < 0 then surplusRound = 0 end
		buff.currentRound = buff.round - surplusRound
	end

	if not self._heroData then
		return
	end
	self._heroData:OnUpdateBuffRound(nowRound)

	FireEvent(EventNames.BUFF_DETAILS_UPDATE,self._heroData)
end
