---出生
function LFightObject:ShowBirth(func)

	if not self:IsOnGridObj() then
		local endFunc = self._birthFunc
		self._birthFunc = nil
		if endFunc then
			endFunc()
		end
		return
	end

	---@type LFightUnit
	local battleUnit = self._battleUnit
	--- 2024/7/15： 目前出生动画由该战斗类型所设定的速度做
	local birthSpeed = battleUnit:GetSpeed()
	battleUnit:SetBirthSpeed(birthSpeed)

	self:SetPosByGrid()

	--出生时候显示
	self._birthFunc = func
	self:KillBirthTween()
	self:KillDeadTween()

	local tweenSeq = self._seqCom:CreateSeq("birthTween")
	local showEffRef = self:GetShowEffRef()
	local showtime = LxResPathUtil.GetSpineAniTime(showEffRef.prefabName, LSpineAniConst.start, 0)
	self:PlayAni(LSpineAniConst.start,false,0,0)

	local alphaFunc = function (value)
		self:SetObjAlpha(value)
	end

	alphaFunc(0)
	local alphaTime = 0.1
	local alpha = self:GetUnintelligibilityAlpha() or 1
	local alphaTween = YXTween.TweenFloat(0,alpha,alphaTime,alphaFunc)
	tweenSeq:AppendCallback(function ()
		self:ShowBirthEffect()
	end)
	tweenSeq:AppendInterval(0.1)
	tweenSeq:Append(alphaTween)

	tweenSeq:AppendInterval(showtime)
	tweenSeq:AppendCallback(function ()
		self:PlayIdleAni()
		self:UpdateHpProgress(self._curHp)
		-- 【G公共支持】删除暗黑战争相关数据
		-- if not self._isDarkWar then
		-- 	self._battleUnit:HideWaitEff()
		-- end

		self:ClearBirthEffect()
	end)

	if self:HasSCard() then
		tweenSeq:AppendCallback(function ()
			self:ShowCardAppear()
		end)
		tweenSeq:AppendInterval(1.2)
		tweenSeq:AppendCallback(function ()
			self:ShowCardAttach()
		end)
		tweenSeq:AppendInterval(1)
	end

	tweenSeq:OnComplete(function()

		local endFunc = self._birthFunc
		self._birthFunc = nil
		if endFunc then
			endFunc()
		end
		self:SetHeroBgVisiable(true)
	end)
	tweenSeq:PlayForward()
end

function LFightObject:SetHeroBgVisiable(visiable)
	CS.ShowObject(self._heroBgTrans,visiable)
end

function LFightObject:ShowCardAppear()
	local decoCtrl = self._battleUnit:GetDecoCtrl()
	local refId = self:GetCardRefId()
	local ref = gModelSorceryCard:GetSorceryCardRefByRefId(refId)
	local spriteName = ref.fightIcon
	spriteName = gLGameLanguage:GetResName(spriteName)

	local effectData =
	{
		effectKey = string.format("%s_appear",self._id),
		loadedCall = function(effect)
			local tran = effect:GetDisplayTrans()
			tran.position = self:GetPosition()
			local spiteTran = CS.FindTrans(tran,ref.fightEff .. '/xian1')
			local spriteRenderer = spiteTran.gameObject:AddComponent(typeof(UnityEngine.SpriteRenderer))
			spriteRenderer.sortingLayerName = "ObjectUp"
			self:SetSpriteRenderer(spiteTran, spriteName)
		end,
		root = self._objRoot,
		resName = ref.fightEff,
	}
	decoCtrl:CreateEffect(effectData)
end

function LFightObject:ShowCardAttach()
	local decoCtrl = self._battleUnit:GetDecoCtrl()
	local refId = self:GetCardRefId()
	local resName = gModelSorceryCard:GetCardAttachEff(refId)
	if not resName then
		return
	end


	local effectData =
	{
		effectKey = string.format("%s_attach",self._id),
		loadedCall = function(effect)
			local tran = effect:GetDisplayTrans()
			tran.localPosition = Vector3.New(0,0.5,0)
		end,
		root = self._objRoot,
		resName = resName,
	}
	decoCtrl:CreateEffect(effectData)
end

function LFightObject:ClearCardEff()
	-- 【G公共支持】删除暗黑战争相关数据
	-- if self._isDarkWar then
	-- 	return
	-- end
	local decoCtrl = self._battleUnit:GetDecoCtrl()
	local key = string.format("%s_attach",self._id)
	decoCtrl:DeleteEffect(key)
	key = string.format("%s_appear",self._id)
	decoCtrl:DeleteEffect(key)
end


function LFightObject:SetPosByGrid()
	self:SetPosition(self._gridPos)
end

function LFightObject:SetHeroBgPos()
	if CS.IsValidObject(self._heroBgTrans) then
		self._heroBgTrans.localPosition = self._gridPos
	end
	if CS.IsValidObject(self._constObjRoot) then
		self._constObjRoot.localPosition = self._gridPos
	end
end

function LFightObject:KillBirthTween()
	self._seqCom:DeleteSeq("birthTween")
end

function LFightObject:LoadBirthEff()
	local showEffRef = self:GetShowEffRef()
	if not showEffRef then
		return
	end
	local decoCtrl = self._battleUnit:GetDecoCtrl()

	local resName = showEffRef.startEffect
	if string.isempty(resName) then
		return
	end

	local key = string.format("%s_birthEffect",self._id)
	self._waitLoadMap = self._waitLoadMap or {}
	self._waitLoadMap[key] = true

	local effectData =
	{
		effectKey = key,
		loadedCall = function(effect)
			if self._waitLoadMap then
				self._waitLoadMap[key] = nil
			end
			local tran = effect:GetDisplayTrans()
			CS.ShowObject(tran,false)
			self:CheckLoadEnd()
		end,
		failCallback = function()
			if self._waitLoadMap then
				self._waitLoadMap[key] = nil
			end
			self:CheckLoadEnd()
		end,
		root = self._objRoot,
		resName = resName,
	}
	decoCtrl:CreateEffect(effectData)

end

function LFightObject:CheckLoadEnd()
	if self._waitLoadMap then
		for k,v in pairs(self._waitLoadMap) do
			if v then
				return
			end
		end
	end

	if self._loadCnt > 0 then
		return
	end

	self:OnBattleObjLoaded()

end

function LFightObject:ShowBirthEffect()
	local decoCtrl = self._battleUnit:GetDecoCtrl()
	local effectKey = string.format("%s_birthEffect",self._id)
	local info = decoCtrl:FindEffectInfoByKey(effectKey)
	if not info then
		return
	end
	local effect = info.effect
	effect:RestartFx()
end

function LFightObject:ClearBirthEffect()
	local decoCtrl = self._battleUnit:GetDecoCtrl()
	local effectKey = string.format("%s_birthEffect",self._id)
	decoCtrl:DeleteEffect(effectKey)
end

