function LFightObject:OnBattleObjLoaded()

	if self._summonAndPet[self._battleObjType] then
		self._isSummonReady = true
	end

	local completeFunc = self._completeFunc
	self._completeFunc = nil
	if completeFunc then
		completeFunc()
	end
end

function LFightObject:GetObjectType()
	return self._battleObjType
end

function LFightObject:CreateBubbleStick(prefabName,offset)

	local bubbleStick = self._bubbleStick
	if not bubbleStick then
		bubbleStick = LBubbleStick:New()
	end

	local dpTarns = self._objRoot
	local topNodePos = self:GetTopNodePos()
	local nowPos = dpTarns.position
	local pos = topNodePos - nowPos + offset
	bubbleStick:CreateBubble(prefabName)
	bubbleStick:SetHeroTrans(dpTarns,pos)
	self._bubbleStick = bubbleStick
end

function LFightObject:ShowBubbleStick(str,time,startTime,prefabName,offset)
	local bubbleStick = self._bubbleStick
	self:CreateBubbleStick(prefabName,offset)
	bubbleStick = self._bubbleStick
	if not bubbleStick then return end
	bubbleStick:SetContent(str,time,startTime)
	bubbleStick:SetVisible(true)
end
function LFightObject:ResetRender(isEnd)

	local order = self:GetRenderOrder()
	self:SetRenderOrder(order)
	self:ToLowerLayer()

	self:ShowBuffEffect(true,isEnd)


end

--function LFightObject:HideBlood()
--	self:ShowBloodStick(false)
--end

function LFightObject:ShowBuffEffect(isShow,isEnd)
	if self._curBuffEffectList then
		if isShow and self:IsDead() then
			isShow = false
		end
		for k,v in ipairs(self._curBuffEffectList) do
			v:SetVisible(isShow,isEnd)
		end
		for k,v in ipairs(self._pliesBuffEffectList) do
			v:SetVisible(isShow,isEnd)
		end
	end
end

function LFightObject:ShowBuffEffect_1(isShow)
	if self._curBuffEffectList then
		if isShow and self:IsDead() then
			isShow = false
		end
		for k,v in ipairs(self._curBuffEffectList) do
			if isShow and v:CheckIsHitShowBuff() then
				v:SetVisible(false)
			else
				v:SetVisible(isShow)
			end
		end
		for k,v in ipairs(self._pliesBuffEffectList) do
			if isShow and v:CheckIsHitShowBuff() then
				v:SetVisible(false)
			else
				v:SetVisible(isShow)
			end
		end
	end
end

