function LFightObject:ToUpperLayer()
	self._isUpperLayer = true


	local layer = "ObjectUp"
	for k,v in ipairs(self._displayObjList) do
		v:SetRenderLayer(layer)
	end


	self:RefreshBuffActLayer()
end

function LFightObject:ToLowerLayer()
	self._isUpperLayer = false

	local layer = "Object"
	for k,v in ipairs(self._displayObjList) do
		v:SetRenderLayer(layer)
	end
	--self._displayObj:SetRenderLayer(layer)

	self:RefreshBuffActLayer()
end

function LFightObject:StartFade(time)

	local tweenSeq = self._seqCom:CreateSeq("alphaSeq")
	local alphaFunc = function(value)
		self:SetObjAlpha(value)
	end
	local alphaTween = YXTween.TweenFloat(1,0,time,alphaFunc):SetEase(DG.Tweening.Ease.InSine)
	tweenSeq:Append(alphaTween)
	tweenSeq:PlayForward()
end

function LFightObject:StartInSitu(effData)
	local playTime = effData.playTime
	local dissipateTime = effData.dissipateTime
	local doFade = dissipateTime and dissipateTime > 0
	local tweenSeq = self._seqCom:CreateSeq("startInSitu")
	local alphaFunc = function(value)
		self:SetObjAlpha(value)
	end
	self._bloodStick:SetVisible(false)
	if doFade then
		local alphaHideTween = YXTween.TweenFloat(1,0,dissipateTime,alphaFunc):SetEase(DG.Tweening.Ease.InSine)
		tweenSeq:Append(alphaHideTween)
		local showTime = playTime - dissipateTime
		tweenSeq:Insert(showTime,
				YXTween.TweenFloat(0,1,dissipateTime,alphaFunc):SetEase(DG.Tweening.Ease.InSine))
		tweenSeq:InsertCallback(showTime + dissipateTime,function()
			self._bloodStick:SetVisible(true)
		end)
	else
		alphaFunc(0)
		tweenSeq:AppendInterval(playTime)
		tweenSeq:AppendCallback(function()
			alphaFunc(1)
			self._bloodStick:SetVisible(true)
		end)
	end
	tweenSeq:PlayForward()
end

function LFightObject:SetObjAlpha(value)
	--print("set alpha "..value)
	for k,v in ipairs(self._displayObjList) do
		v:SetAlpha(value)
	end
end

--- 隐匿状态透明度设置
function LFightObject:SetUnintelligibilityAlpha(value,isRemove)
	if isRemove then
		self._unintelligibilityAlpha = nil
	else
		self._unintelligibilityAlpha = value
	end
	self:SetObjAlpha_1(value)
end

function LFightObject:SetObjAlpha_1(value)
	local dpInValidNum = 0
	for k,v in ipairs(self._displayObjList) do
		if v:IsDpValid() then
			v:SetAlpha(value)
		else
			dpInValidNum = dpInValidNum + 1
		end
	end
	if dpInValidNum > 0 then
		self._saveAlpha = value
	end
end

function LFightObject:GetUnintelligibilityAlpha()
	return self._unintelligibilityAlpha
end

function LFightObject:SetHasBuffEffectStatus(bShow)
	if not self._battleUnit then return end
	if self._battleUnit:IsDestroy() then return end
	self._battleUnit:ResetBuffEffect(self:GetId(),bShow)
end

--- 战斗对象状态
--- state:
--- 0 ： 隐藏
--- 1 ： 显示
function LFightObject:SetBattleObjState(state)
	local isShow = state == 1
	if isShow and self:IsDead() then
		isShow = false
	end
	local alpha = isShow and 1 or 0

	--- 若是隐匿状态下 alpha 设置
	if state == 1 and isShow then
		local unintelligibilityAlpha = self:GetUnintelligibilityAlpha()
		if unintelligibilityAlpha and unintelligibilityAlpha > 0 then
			alpha = unintelligibilityAlpha
		end
	end
	self:SetObjAlpha(alpha)
	if self._bloodStick then
		self._bloodStick:SetVisible(isShow)
	end
end

function LFightObject:IsUpperLayer()
	return self._isUpperLayer or false
end

function LFightObject:ResetAlpha()
	self._seqCom:DeleteSeq("alphaSeq")
	self:UpdateAlpha()
end

--- 若是隐匿状态下 alpha 设置
function LFightObject:UpdateAlpha(defaultAlpha)
	local alpha = defaultAlpha or 1
	local unintelligibilityAlpha = self:GetUnintelligibilityAlpha()
	if unintelligibilityAlpha and unintelligibilityAlpha > 0 then
		alpha = unintelligibilityAlpha
	end
	self:SetObjAlpha(alpha)
end

function LFightObject:ChangeIndex(effect,duration)

	local oldIndex = effect.oldIndex
	local newIndex = effect.newIndex

	--printErrorN(string.format("changeIndex id %s,cur %s,newI %s, oldI %s",self._id,self._index,newIndex,oldIndex))

	if self._index == oldIndex then
		self:ChangeIndexPass(effect,duration)
		return
	elseif self._index == newIndex then
		self._index = oldIndex
	else
		return
	end

	local order = self:GetRenderOrder()
	self:SetRenderOrder(order)

	local gridPos = self._battleUnit:GetGridPosByIndex(self._side,self._index)

	self._gridPos = gridPos

	self:StartMove(gridPos,duration)
end

function LFightObject:ChangeIndexPass(effect,duration)
	self._index = effect.newIndex


	local passPosList = {}
	local passList = effect.wayIndexList or {}
	for k,v in ipairs(passList) do
		local gridPos = self._battleUnit:GetGridPosByIndex(self._side,v)
		table.insert(passPosList,gridPos)
	end

	local gridPos = self._battleUnit:GetGridPosByIndex(self._side,self._index)
	table.insert(passPosList,gridPos)

	self._gridPos = gridPos

	passPosList = self:ModifyMoveOffset(passPosList)
    local time =  duration/#passPosList
    for k,v in ipairs(passPosList) do
        self:InsertMovePara(v,time)
    end


end

function LFightObject:OnMoveUpdate()
	if not self._moveParaList then
		return
	end

	if self._moveActor:IsMoving() then
		return
	end

	local para = table.remove(self._moveParaList,1)
	if not para then
		self._moveParaList = nil
		return
	end

    self:StartMove(para.pos,para.time)

end

function LFightObject:ModifyMoveOffset(posList)
	local cnt = #posList
	if cnt >= 2 then
		local newList = {}
		newList[1] = posList[1]
		for k=2,cnt do
			local lastPos = posList[k-1]
			local curPos = posList[k]
			local newPos = Vector3.Lerp(lastPos,curPos,0.9)
			newList[k] = newPos
		end

		return newList
	end

	return posList
end


function LFightObject:SetSkillPlaying(isPlaying)
	self._isSkillPlaying = isPlaying
	if isPlaying then
		--self:SetObjAlpha(1)
		self:UpdateAlpha()
	end
end

function LFightObject:RefreshBuffAct(curList)
	if not self._curBuffActList then
		self._curBuffActList = {}
	end

	local dpTrans = self._objRoot -- self._displayObj:GetDisplayTrans()
	if not CS.IsValidObject(dpTrans) then return end

    local isLeft = self:GetActOn() == LFightConst.SIDE_TEAM_B
	local removeList = {}
	for k,v in pairs(self._curBuffActList) do
		if not curList[k] then
			table.insert(removeList,{ buffId= k})
		end
	end

	local renderOrder = self:GetRenderOrder()
	local refreshList = {}
	for k,v in  pairs(curList) do
		local resName = v.buffAct.spineName
		local aniName,lastAni
		if LOG_INFO_ENABLED then
			print(string.format("buff id %s ,cnt %s",k,v.cnt))
		end
		for k1,v1 in ipairs(v.buffAct.aniList) do
            lastAni = v1.ani
			if v.cnt <= v1.cnt then
				aniName = v1.ani
                break
			end
		end
        if aniName == nil then
            aniName = lastAni
        end

		local data = {
			trans = dpTrans,
			resName = resName,
			sorting = renderOrder,
			key = k,
            isLeft = isLeft,
			endFunc = function(spine)
				spine:PlayAnimation(0,aniName,true,false,0)
			end
		}
		table.insert(refreshList,data)
	end

	self:ShowBuffAct(refreshList,removeList)

	self._curBuffActList = curList
end

function LFightObject:ShowBuffAct(refreshList,removeList)
	for k,v in pairs(refreshList) do
		self._buffSpineCtrl:MakeObject(v)
	end

	for k,v in pairs(removeList) do
		self._buffSpineCtrl:DestroyByKey(v.buffId)
	end
end

function LFightObject:RefreshBuffActLayer(order)
	local renderOrder = order or self:GetRenderOrder()
	local renderLayer = self:GetRenderLayer()
	self._buffSpineCtrl:RefreshAllRenderLayer(renderLayer,renderOrder + 1)
end

function LFightObject:RefreshBuffBar()
	local statisticsMap = self._statisticsMap or {}
	local list = {}
	local buffUniqueId
	for k,v in ipairs(self._buffList) do
		local buffUIPara = gModelSkill:GetBuffBuffUi(v.buffId)
		if buffUIPara then
			buffUniqueId = v.buffUniqueId
			local data = list[v.buffId]
			if not data then
				data = {}
				list[v.buffId] = data
				data.buffUIPara = buffUIPara
				data.cnt = 0
			end
			data.cnt = data.cnt + 1
			data.statisticsData = statisticsMap[buffUniqueId]
		end
	end


	self:RefreshBuffBarShow(list)
end

function LFightObject:PlayAni_Actor(ani,loop,mixTime)
	for k,v in ipairs(self._displayObjList) do
		v:SetAnimationTimeScale(1)
		v:PlayAnimation(0,ani,loop,false,mixTime)
	end
end

function LFightObject:SetAniTimeScale_Actor(timeScale)
	for k,v in ipairs(self._displayObjList) do
		v:SetAnimationTimeScale(timeScale)
	end
end

function LFightObject:PlayAni_TreatAni(time)
	self._playTreatStatus = true
	self:PlayAni("resurrected", false, time + 0.1)
end

