function LFightObject:SetHideBloodKey(key)
	if not self._hideBloodKey then
		self._hideBloodKey= {}
	end

	self._hideBloodKey[key] = true

	self:CheckShowBlood()
end

function LFightObject:ReleaseHideKey(key)
	if self._hideBloodKey then
		self._hideBloodKey[key] = nil
	end

	self:CheckShowBlood()
end

function LFightObject:CheckShowBlood()
	local showBlood = true
	if not table.isempty(self._hideBloodKey) then
		showBlood = false
	end

	local isHide = self:IsSummonHideBlood()
	if isHide then
		showBlood = false
	end


	self:ShowBloodStick(showBlood)
end

function LFightObject:ShowSummonBirth()
	self._isSummonReady = false

	self:SetPosByGrid()
	self:SetObjAlpha(0)
	local seq = self._seqCom:CreateSeq("summonBirth")
	if self._battleObjType == LFightConst.OBJ_PET then
		seq:AppendCallback(function ()
			self:ShowBirthEffect()
		end)
		seq:AppendInterval(3)
	else
		seq:AppendInterval(1)
	end

	local alphaFunc = function (value)
		self:SetObjAlpha(value)
	end
	local alpha = self:GetUnintelligibilityAlpha() or 1
	local alphaTween = YXTween.TweenFloat(0,alpha,1,alphaFunc):SetEase(DG.Tweening.Ease.InSine)
	seq:Join(alphaTween)
	seq:OnComplete(function ()
		self._isSummonReady = true
		self:CheckShowBlood()
		self:ClearBirthEffect()
	end)
	seq:PlayForward()

end

function LFightObject:IsSummonHeroReady()
	return self._isSummonReady
end

function LFightObject:IsObjReady()
	if self._summonAndPet[self._battleObjType] then
		return self:IsSummonHeroReady()
	else
		return true
	end
end

function LFightObject:IsSummonHideBlood()
	if not self._summonAndPet[self._battleObjType]  then
		return
	end

	if table.isempty(self._buffList) then
		return
	end

	for k,v in pairs(self._buffList) do
		local statelist = gModelBattle:GetBuffStateIDByBuffID(v.buffId)
		for k1,v1 in ipairs(statelist) do
			if v1 == LBuffStateConst.BUFF_STATE_SUMMON_UNSELECT then
				return true
			end
		end
	end
end

function LFightObject:UpdateCdRound(roundCd)

	self._roundCd = roundCd

	if not self._bloodStick then
		return
	end

	self._bloodStick:ShowCdInfo(roundCd)
end


function LFightObject:GetPlaySoundBattle(soundBattle,effData)
	if not self:IsOnGridObj() then return soundBattle end

	if not self._heroData then return soundBattle end

	return self._heroData:GetPlaySoundBattle(soundBattle,effData)
end

function LFightObject:GetObjScale()
	return self._scale
end

function LFightObject:GetBuffListByRefId(refId)
	if not self._buffList then return {} end

	local list = {}
	for k,v in pairs(self._buffList) do
		if v.buffId == refId then
			table.insert(list,v)
		end
	end
	return list
end

