	self._replaceIdleAni = aniName
end

---@return string 替换 idle 动画
function LFightObject:GetReplaceIdle()
	return self._replaceIdleAni
end

function LFightObject:GetObjRoot()
	return self._objRoot
end

function LFightObject:GetConstObjRoot()
	return self._constObjRoot
end

function LFightObject:GetRootTrans()
	return self._rootTrans
end
-----------------------------------------------------------------
function LFightObject:Destroy()
	self:KillBirthTween()
	self:KillDeadTween()

	if self._bloodStick then
		self._bloodStick:Destroy()
		self._bloodStick = nil
	end

	if self._bubbleStick then
		self._bubbleStick:DestroyBubble()
		self._bubbleStick = nil
	end

	for k,v in ipairs(self._displayObjList) do
		v:Destroy()
	end
	self._displayObjList = nil

	self:ClearCardEff()

	if CS.IsValidObject(self._objRoot) then
		LxResUtil.DestroyObject(self._objRoot.gameObject)
	end
	self._objRoot = nil

	if CS.IsValidObject(self._constObjRoot) then
		LxResUtil.DestroyObject(self._constObjRoot.gameObject)
	end
	self._constObjRoot = nil

	if CS.IsValidObject(self._heroBgTrans) then
		LxResUtil.DestroyObject(self._heroBgTrans.gameObject)
	end
	self._heroBgTrans = nil




	self:DestroyAllBuff()

	if self._objHud then
		self._objHud:Destroy()
		self._objHud = nil
	end

	if self._seqCom then
		self._seqCom:Destroy()
		self._seqCom= nil
	end

	LxNodeBase.Dispose(self)

	self._bDestoryed = true
end

------------------------------------------------------------------
return LFightObject



